const clearPublicFormDrafts=()=>{try{const keep=new Set([SK.settings,SK.subs,'zkid_lang']); const patterns=['draft','courseForm','consultForm','shippingForm','paymentForm','publicForm','zkid_course','zkid_form']; [localStorage,sessionStorage].forEach(store=>{for(let i=store.length-1;i>=0;i--){const k=store.key(i)||''; if(!keep.has(k)&&patterns.some(p=>k.toLowerCase().includes(p.toLowerCase()))) store.removeItem(k);}})}catch{}};
const IMAGE_BUCKET='images';
const allowedImageTypes=['image/jpeg','image/jpg','image/png','image/webp'];
const isStorageUrl=(u?:string)=>!!u&&/^https?:\/\/.+\/storage\/v1\/object\/public\//.test(u);
const storagePathFromUrl=(u:string)=>{try{const m=new URL(u).pathname.match(/\/storage\/v1\/object\/public\/images\/(.+)$/);return m?decodeURIComponent(m[1]):null}catch{return null}};
const deleteStoredImage=async(u?:string)=>{try{if(!isSupabaseConfigured||!supabase||!u||!isStorageUrl(u))return;const path=storagePathFromUrl(u);if(path)await supabase.storage.from(IMAGE_BUCKET).remove([path])}catch(e){console.warn('Could not delete old image',e)}};
const compressImage=async(file:File,maxBytes=1024*1024):Promise<Blob>=>{if(!allowedImageTypes.includes(file.type))throw new Error('فرمت تصویر مجاز نیست. فقط jpg، jpeg، png و webp پذیرفته می‌شود.'); if(file.size<=maxBytes)return file; const bmp=await createImageBitmap(file); const canvas=document.createElement('canvas'); const scale=Math.min(1,Math.sqrt(maxBytes/file.size)); canvas.width=Math.max(1,Math.round(bmp.width*scale)); canvas.height=Math.max(1,Math.round(bmp.height*scale)); const ctx=canvas.getContext('2d'); if(!ctx)return file; ctx.drawImage(bmp,0,0,canvas.width,canvas.height); let q=.82; const type=file.type==='image/png'?'image/webp':file.type; const toBlob=()=>new Promise<Blob>((res,rej)=>canvas.toBlob(b=>b?res(b):rej(new Error('compression failed')),type,q)); let out=await toBlob(); while(out.size>maxBytes&&q>.45){q-=.12; out=await toBlob()} return out};
const blobToDataUrl=(blob:Blob)=>new Promise<string>((res,rej)=>{const r=new FileReader();r.onload=()=>res(String(r.result));r.onerror=rej;r.readAsDataURL(blob)});
const fileToData=async(f:File,oldUrl?:string,folder='uploads')=>{const compressed=await compressImage(f); if(isSupabaseConfigured&&supabase){const ext=(compressed.type.split('/')[1]||'jpg').replace('jpeg','jpg'); const path=`${folder}/${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`; const {error}=await supabase.storage.from(IMAGE_BUCKET).upload(path,compressed,{contentType:compressed.type,upsert:false}); if(error)throw error; await deleteStoredImage(oldUrl); const {data}=supabase.storage.from(IMAGE_BUCKET).getPublicUrl(path); return data.publicUrl} const dataUrl=await blobToDataUrl(compressed); if(dataUrl.length>1024*1024*1.4)throw new Error('حجم تصویر زیاد است. لطفاً تصویر کوچک‌تری انتخاب کنید.'); return dataUrl};

