function mergeSettings(raw:any){const m={...defaultSettings,...(raw||{})};m.formFields={...defaultSettings.formFields,...(raw?.formFields||{})}; if(!raw?.formFields?.notes?.placeholder||raw.formFields.notes.placeholder==='توضیحات تکمیلی در صورت نیاز...') m.formFields.notes={...m.formFields.notes,placeholder:defaultSettings.formFields.notes.placeholder}; if(!raw?.photoUrl||raw.photoUrl===placeholder) m.photoUrl=PROFILE_PHOTO;m.contacts={...defaultSettings.contacts,...(raw?.contacts||{})};m.contactIcons={...defaultSettings.contactIcons,...(raw?.contactIcons||{})};m.translations={fa:{...faDict,...(raw?.translations?.fa||{})},en:{...enDict,...(raw?.translations?.en||{})}};m.contactVisibility={...defaultSettings.contactVisibility,...(raw?.contactVisibility||{})};m.countryCodes=raw?.countryCodes||defaultSettings.countryCodes;m.courseTabs=raw?.courseTabs||defaultSettings.courseTabs;m.shippingMethods={iran:raw?.shippingMethods?.iran||defaultSettings.shippingMethods.iran,intl:raw?.shippingMethods?.intl||defaultSettings.shippingMethods.intl};m.delivery={...defaultSettings.delivery,...(raw?.delivery||{})};m.banks=raw?.banks||defaultSettings.banks;m.i18n={...defaultSettings.i18n,...(raw?.i18n||{})};return m;}

function validPhone(local:string, country:any){const clean=p2e(local).replace(/[\s\-()]/g,''); if(!clean||/^(\d)\1+$/.test(clean)) return false; try{return new RegExp(country?.regex||'^\\d{7,}$').test(clean)}catch{return /^\d{7,}$/.test(clean)}}
function fullPhone(cc:string, local:string){return `${cc}${p2e(local).replace(/[\s\-().]/g,'')}`}

